def get_arena_name(year):
    name_changes = {
        2002: "SBC Center",
        2005: "AT&T Center",
        2023: "Frost Bank Center"
    }
    # Determine the most recent name change before or in the given year
    for change_year in sorted(name_changes.keys()):
        if year >= change_year:
            return name_changes[change_year]
    return "Arena not yet built"

# Example usage:
print(get_arena_name(2006))  # Output: AT&T Center
print(get_arena_name(2020))  # Output: AT&T Center
print(get_arena_name(2023))  # Output: Frost Bank Center
